                } catch (e: Exception) {
                    cont?.resume(SocialAuthResult.Error(SocialProvider.GOOGLE, e))
                }
            } else {
                cont?.resume(SocialAuthResult.Cancelled(SocialProvider.GOOGLE))
            }
        }
    }

    override suspend fun signIn(activity: Activity): SocialAuthResult = suspendCancellableCoroutine { cont ->
        if (googleSignInClient == null || launcher == null) {
            if (activity is AppCompatActivity) attach(activity)
