    suspend fun signInWithGoogle(activity: Activity): SocialAuthResult = googleClient.signIn(activity)
    fun signOutAll(context: Context) {
        facebookClient.signOut(context)
        googleClient.signOut(context)
    }

    fun onFacebookActivityResult(requestCode: Int, resultCode: Int, data: Intent?): Boolean {
        return facebookClient.onActivityResult(requestCode, resultCode, data)
    }

    fun attachGoogle(activity: AppCompatActivity) {
        googleClient.attach(activity)
    }
}

